    {
      "text": "那個人長得很高，而且很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, érqiě hěn shòu.",
      "pinyin_numeric": "na4 ge5 ren2 zhang3 de5 hen3 gao1, er2qie3 hen3 shou4.",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬해요."
    },
    {
      "text": "那個人是我朋友，他個性很幽默。",
      "pinyin": "Nà ge rén shì wǒ péngyou, tā gèxìng hěn yōumò.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 wo3 peng2you5, ta1 ge4xing4 hen3 you1mo4.",
      "translation_en": "That person is my friend; he has a very humorous personality.",
      "translation_ko": "그 사람은 제 친구인데, 성격이 매우 유머러스해요."
    },
    {
      "text": "那個人是誰？他看起來很年輕。",
      "pinyin": "Nà ge rén shì shuí? Tā kàn qǐlái hěn niánqīng.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 shui2? Ta1 kan4 qi3lai2 hen3 nian2qing1.",
      "translation_en": "Who is that person? He looks very young.",
      "translation_ko": "저 사람은 누구예요? 그는 매우 젊어 보여요."
    },
    {
      "text": "那個人戴眼鏡，穿著黑色上衣。",
      "pinyin": "Nà ge rén dài yǎnjìng, chuān zhuó hēisè shàngyī.",
      "pinyin_numeric": "na4 ge5 ren2 dai4 yan3jing4, chuan1 zhuo2 hei1se4 shang4yi1.",
      "translation_en": "That person wears glasses and is dressed in a black top.",
      "translation_ko": "저 사람은 안경을 쓰고, 검은색 상의를 입고 있어요."
    },
    {
      "text": "那個人是我哥哥，他個性很認真。",
      "pinyin": "Nà ge rén shì wǒ gēge, tā gèxìng hěn rènzhēn.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 wo3 ge1ge5, ta1 ge4xing4 hen3 ren4zhen1.",
      "translation_en": "That person is my older brother; he has a very serious personality.",
      "translation_ko": "저 사람은 제 오빠인데, 성격이 매우 진지해요."
    },
    {
      "text": "那個人長得漂亮，而且很友善。",
      "pinyin": "Nà ge rén zhǎng de piàoliang, érqiě hěn yǒushàn.",
      "pinyin_numeric": "na4 ge5 ren2 zhang3 de5 piao4liang5, er2qie3 hen3 you3shan4.",
      "translation_en": "That person is pretty and also very friendly.",
      "translation_ko": "저 사람은 예쁘게 생겼고, 또한 매우 친절해요."
    },
    {
      "text": "那個人是我妹妹，她個性很活潑。",
      "pinyin": "Nà ge rén shì wǒ mèimei, tā gèxìng hěn huópō.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 wo3 mei4mei5, ta1 ge4xing4 hen3 huo2po1.",
      "translation_en": "That person is my younger sister; she has a very lively personality.",
      "translation_en": "That person is my younger sister; she has a very lively personality.",
      "translation_ko": "저 사람은 제 여동생인데, 성격이 매우 활발해요."
    },
    {
      "text": "那個人看起來很聰明，而且很溫柔。",
      "pinyin": "Nà ge rén kàn qǐlái hěn cōngmíng, érqiě hěn wēnróu.",
      "pinyin_numeric": "na4 ge5 ren2 kan4 qi3lai2 hen3 cong1ming2, er2qie3 hen3 wen1rou2.",
      "translation_en": "That person looks very smart and also very gentle.",
      "translation_ko": "저 사람은 매우 똑똑해 보이고, 또한 매우 부드러워요."
    },
    {
      "text": "那個人是我媽媽，她個性很大方。",
      "pinyin": "Nà ge rén shì wǒ māma, tā gèxìng hěn dàfāng.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 wo3 ma1ma5, ta1 ge4xing4 hen3 da4fang1.",
      "translation_en": "That person is my mother; she has a very generous personality.",
      "translation_ko": "저 사람은 제 엄마인데, 성격이 매우 대범해요."
    },
    {
      "text": "那個人是誰？他好像很害羞。",
      "pinyin": "Nà ge rén shì shuí? Tā hǎoxiàng hěn hàixiū.",
      "pinyin_numeric": "na4 ge5 ren2 shi4 shui2? Ta1 hao3xiang4 hen3 hai4xiu1.",
      "translation_en": "Who is that person? He seems very shy.",
      "translation_ko": "저 사람은 누구예요? 그는 매우 부끄러워하는 것 같아요."
    }
  ]
}
